const users = {
  'user1': { id: 'user1', name: 'Alice' },
  'user2': { id: 'user2', name: 'Bob' },
};

const messages = {
  'msg1': { id: 'msg1', userId: 'user1', text: 'Hello Bob!', timestamp: 1678900000000 },
  'msg2': { id: 'msg2', userId: 'user2', text: 'Hi Alice!', timestamp: 1678900001000 },
};

function addUser(users, user) {
  return { ...users, [user.id]: user };
}

function addMessage(messages, message) {
  return { ...messages, [message.id]: message };
}

// Usage:
const updatedUsers = addUser(users, { id: 'user3', name: 'Charlie' });
const updatedMessages = addMessage(messages, { id: 'msg3', userId: 'user3', text: 'Hey everyone!', timestamp: Date.now() });

function getMessagesByUser(messages, userId) {
  return Object.values(messages).filter(message => message.userId === userId);
}

// Example usage:
const aliceMessages = getMessagesByUser(updatedMessages, 'user1');
console.log(aliceMessages);

